// تحليل شامل لسلوك المستخدمين
const inputData = items[0].json;
const { action, userId, userData, timestamp } = inputData;

// تصنيف أنواع الأنشطة
const actionTypes = {
  'user_registered': {
    category: 'acquisition',
    priority: 'high',
    followUp: 'welcome_sequence',
    kpi: 'new_users'
  },
  'user_logged_in': {
    category: 'engagement',
    priority: 'medium',
    followUp: 'session_tracking',
    kpi: 'active_users'
  },
  'profile_updated': {
    category: 'activation',
    priority: 'high',
    followUp: 'completion_check',
    kpi: 'profile_completion'
  },
  'listing_created': {
    category: 'conversion',
    priority: 'very_high',
    followUp: 'listing_optimization',
    kpi: 'listings_created'
  }
};

// الحصول على معلومات النشاط
const actionInfo = actionTypes[action] || {
  category: 'other',
  priority: 'low',
  followUp: 'basic_tracking',
  kpi: 'misc_actions'
};

// تحليل ملف المستخدم
const userAnalysis = {
  isNewUser: action === 'user_registered',
  hasCompletProfile: userData && userData.name && userData.phone && userData.location,
  preferredLanguage: userData?.language || 'bg',
  accountType: userData?.accountType || 'individual',
  verificationStatus: userData?.emailVerified || false
};

// تحديد مستوى المستخدم
let userLevel = 'basic';
if (userAnalysis.hasCompletProfile && userAnalysis.verificationStatus) {
  userLevel = 'verified';
}
if (userData?.listingCount > 5) {
  userLevel = 'power_user';
}
if (userData?.accountType === 'dealer') {
  userLevel = 'business';
}

// اقتراحات التحسين للمستخدم
let recommendations = [];
if (!userAnalysis.hasCompletProfile) {
  recommendations.push('Complete profile for better visibility');
}
if (!userAnalysis.verificationStatus) {
  recommendations.push('Verify email for full access');
}
if (userLevel === 'basic' && action === 'listing_created') {
  recommendations.push('Consider upgrading to premium features');
}

// تحليل التوقيت والسلوك
const behaviorAnalysis = {
  timestamp: new Date(timestamp),
  hour: new Date(timestamp).getHours(),
  dayOfWeek: new Date(timestamp).getDay(),
  isBusinessHours: new Date(timestamp).getHours() >= 9 && new Date(timestamp).getHours() <= 17,
  isWeekend: [0, 6].includes(new Date(timestamp).getDay()),
  timeZone: 'Europe/Sofia'
};

// تحديد الإجراءات التلقائية المطلوبة
let automatedActions = [];
if (action === 'user_registered') {
  automatedActions.push('send_welcome_email');
  automatedActions.push('setup_onboarding_sequence');
}
if (action === 'listing_created') {
  automatedActions.push('send_listing_confirmation');
  automatedActions.push('start_promotion_campaign');
}
if (!userAnalysis.verificationStatus && userLevel !== 'basic') {
  automatedActions.push('send_verification_reminder');
}

// تحليل القيمة التجارية
const businessValue = {
  ltv_potential: userLevel === 'business' ? 'high' : userLevel === 'verified' ? 'medium' : 'low',
  engagement_score: (userAnalysis.hasCompletProfile ? 30 : 0) + 
                   (userAnalysis.verificationStatus ? 40 : 0) + 
                   (userData?.listingCount || 0) * 10,
  conversion_likelihood: actionInfo.category === 'conversion' ? 'high' : 
                        actionInfo.category === 'activation' ? 'medium' : 'low'
};

// تحديد قطاعات المستخدمين
let userSegment = 'new_visitor';
if (userLevel === 'business') userSegment = 'business_user';
else if (userLevel === 'power_user') userSegment = 'power_user';
else if (userLevel === 'verified') userSegment = 'active_user';
else if (userAnalysis.isNewUser) userSegment = 'new_user';

return [{
  json: {
    userId,
    action,
    actionInfo,
    userAnalysis,
    userLevel,
    userSegment,
    recommendations,
    behaviorAnalysis,
    automatedActions,
    businessValue,
    processedAt: new Date().toISOString(),
    requiresFollowUp: actionInfo.priority === 'high' || actionInfo.priority === 'very_high'
  }
}];
